import{_ as r,C as i,o,c as n,j as t,a as s,E as l,a4 as c}from"./chunks/framework.CyI4nVbD.js";const b=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"general/introduction.md","filePath":"general/introduction.md"}'),d={name:"general/introduction.md"};function u(h,e,p,f,g,m){const a=i("CifDemo");return o(),n("div",null,[e[0]||(e[0]=t("h1",{id:"introduction",tabindex:"-1"},[s("Introduction "),t("a",{class:"header-anchor",href:"#introduction","aria-label":'Permalink to "Introduction"'},"​")],-1)),e[1]||(e[1]=t("p",null,"CifVis is a JavaScript library and web component for visualizing crystal structures from crystallographic information files (CIF), powered by Three.js. Atoms, bonds and hydrogen bonds are displayed as entered in the CIF. Everything — from CIF parsing, to structure construction, to display — runs locally in your browser; there is no server component.",-1)),l(a,{src:"/cif/sucrose.cif",caption:"Sucrose — drag to rotate, wheel to zoom, click atoms and bonds to select them.",style:{"aspect-ratio":"16 / 9"}}),e[2]||(e[2]=c('<h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li>Interactive 3D visualization of crystal structures</li><li>Support for anisotropic displacement parameters (ADPs)</li><li>Display of bonds and hydrogen bonds</li><li>Disorder group handling</li><li>Crystal symmetry growing of structures</li><li>Progressive difference-density maps from FCF data or observed reflections plus an IAM calculation</li><li>Custom complex coefficients for deformation-density maps, with symmetry-aware surface reuse</li><li>Multi-block CIF selection in the playground and widget API</li><li>Collision-free, opt-in <a href="./../labels/">atom labels</a></li><li>Touch and mouse controls</li><li>Widget for a complete packaged solution</li></ul><h2 id="two-ways-to-use-cifvis" tabindex="-1">Two ways to use CifVis <a class="header-anchor" href="#two-ways-to-use-cifvis" aria-label="Permalink to &quot;Two ways to use CifVis&quot;">​</a></h2><p><strong>The widget.</strong> <code>&lt;cifview-widget&gt;</code> is a browser custom element: include one script, add one HTML tag, and you have an interactive structure viewer with toggle buttons, captions, and selection feedback. If you want a structure on a web page with minimal code, start with <a href="./../widget/getting-started.html">Widget → Getting started</a>.</p><p><strong>The library.</strong> Underneath the widget sits a layered JavaScript library: a CIF parser, a crystallographic structure model with filters, a density-map pipeline, and a Three.js rendering layer orchestrated by <code>CrystalViewer</code>. If you are building your own GUI, batch tooling, or embedding structures in an existing Three.js scene, start with <a href="./../library/getting-started.html">JS Library → Getting started</a>.</p><p>Both share one <code>options</code> schema — see the <a href="./../reference/">Options Reference</a> — and the <a href="./../gallery/">Gallery</a> shows the kinds of applications you can build with either.</p><h2 id="try-it" tabindex="-1">Try it <a class="header-anchor" href="#try-it" aria-label="Permalink to &quot;Try it&quot;">​</a></h2><p>The <a href="https://niolon.github.io/cifvis/" target="_blank" rel="noreferrer">interactive playground</a> lets you load your own CIF file (plus FCF or Gaussian Cube files) and explore it directly. A subset of viewer options can be set through URL query parameters, e.g. <code>?contours=best-fit</code> for a planar contour section.</p><h2 id="license-and-citation" tabindex="-1">License and citation <a class="header-anchor" href="#license-and-citation" aria-label="Permalink to &quot;License and citation&quot;">​</a></h2><p>CifVis is written by Paul Niklas Ruth and released under the <a href="https://www.mozilla.org/en-US/MPL/2.0/" target="_blank" rel="noreferrer">Mozilla Public License 2.0</a>. The source is on <a href="https://github.com/niolon/cifvis" target="_blank" rel="noreferrer">GitHub</a>; the package is published on npm as <a href="https://www.npmjs.com/package/cifvis" target="_blank" rel="noreferrer"><code>cifvis</code></a>.</p>',10))])}const w=r(d,[["render",u]]);export{b as __pageData,w as default};
